// Install dependencies
// npm install memjs aws-sdk @aws-sdk/client-elasticache

import Memjs from 'memjs';
import { ElastiCacheClient, DescribeCacheClustersCommand } from '@aws-sdk/client-elasticache';

// Configure ElastiCache Memcached cluster (Terraform)
const terraformConfig = `
resource "aws_elasticache_cluster" "memcached" {
  cluster_id           = "secure-memcached-cluster"
  engine               = "memcached"
  node_type            = "cache.t3.micro"
  num_cache_nodes      = 2
  parameter_group_name = "default.memcached1.6"
  port                 = 11211

  # Security: Deploy in private subnet only
  subnet_group_name    = aws_elasticache_subnet_group.private.name
  security_group_ids   = [aws_security_group.memcached.id]

  # Encryption at rest
  snapshot_retention_limit = 5
  snapshot_window         = "03:00-05:00"

  # Maintenance window
  maintenance_window = "sun:05:00-sun:07:00"

  # Logging
  log_delivery_configuration {
    destination      = aws_cloudwatch_log_group.memcached.name
    destination_type = "cloudwatch-logs"
    log_format       = "json"
    log_type         = "slow-log"
  }

  tags = {
    Name        = "secure-memcached"
    Environment = "production"
  }
}

resource "aws_elasticache_subnet_group" "private" {
  name       = "memcached-private-subnet"
  subnet_ids = var.private_subnet_ids
}

resource "aws_security_group" "memcached" {
  name        = "elasticache-memcached"
  description = "Security group for ElastiCache Memcached"
  vpc_id      = var.vpc_id

  # Only allow from application tier
  ingress {
    from_port       = 11211
    to_port         = 11211
    protocol        = "tcp"
    security_groups = [aws_security_group.app.id]
  }
}
`;

// Node.js application code
class SecureMemcachedClient {
  private client: Memjs.Client;

  constructor() {
    // Get ElastiCache endpoint from AWS SDK
    const endpoint = process.env.ELASTICACHE_ENDPOINT || 'secure-memcached-cluster.abc123.cfg.use1.cache.amazonaws.com:11211';

    // Create client with security best practices
    this.client = Memjs.Client.create(endpoint, {
      retries: 3,
      retry_delay: 0.2,
      expires: 3600,
      logger: console,
      timeout: 1, // 1 second timeout
      keepAlive: true,
      keepAliveDelay: 30000 // 30 seconds
    });
  }

  async get(key: string): Promise<string | null> {
    try {
      const { value } = await this.client.get(key);
      return value ? value.toString() : null;
    } catch (error) {
      console.error('Memcached GET error:', error);
      return null;
    }
  }

  async set(key: string, value: string, ttl: number = 3600): Promise<boolean> {
    try {
      await this.client.set(key, value, { expires: ttl });
      return true;
    } catch (error) {
      console.error('Memcached SET error:', error);
      return false;
    }
  }

  async delete(key: string): Promise<boolean> {
    try {
      await this.client.delete(key);
      return true;
    } catch (error) {
      console.error('Memcached DELETE error:', error);
      return false;
    }
  }

  async close(): Promise<void> {
    await this.client.close();
  }
}

// Usage example
const cache = new SecureMemcachedClient();

async function example() {
  await cache.set('user:1234', JSON.stringify({ name: 'John', email: 'john@example.com' }), 600);
  const user = await cache.get('user:1234');
  console.log('User from cache:', user);
}

# Azure DDoS Protection Standard (Terraform)
cat > ddos-protection.tf << 'EOF'
resource "azurerm_network_ddos_protection_plan" "main" {
  name                = "prod-ddos-protection"
  resource_group_name = azurerm_resource_group.main.name
  location            = azurerm_resource_group.main.location

  tags = {
    environment = "production"
    purpose     = "DDoS mitigation"
  }
}

resource "azurerm_virtual_network" "main" {
  name                = "prod-vnet"
  resource_group_name = azurerm_resource_group.main.name
  location            = azurerm_resource_group.main.location
  address_space       = ["10.0.0.0/16"]

  # Enable DDoS protection
  ddos_protection_plan {
    id     = azurerm_network_ddos_protection_plan.main.id
    enable = true
  }
}

# Configure DDoS alerts
resource "azurerm_monitor_metric_alert" "ddos_attack" {
  name                = "ddos-attack-detected"
  resource_group_name = azurerm_resource_group.main.name
  scopes              = [azurerm_public_ip.main.id]
  description         = "Alert when DDoS attack detected on public IP"
  severity            = 0
  frequency           = "PT1M"
  window_size         = "PT5M"

  criteria {
    metric_namespace = "Microsoft.Network/publicIPAddresses"
    metric_name      = "UnderDDoSAttack"
    aggregation      = "Maximum"
    operator         = "GreaterThan"
    threshold        = 0
  }

  action {
    action_group_id = azurerm_monitor_action_group.main.id
  }
}

resource "azurerm_monitor_action_group" "main" {
  name                = "ddos-response-team"
  resource_group_name = azurerm_resource_group.main.name
  short_name          = "ddosalert"

  email_receiver {
    name          = "security-team"
    email_address = "security@company.com"
  }

  webhook_receiver {
    name        = "pagerduty"
    service_uri = "https://events.pagerduty.com/integration/xxx/enqueue"
  }
}
EOF

# AWS Shield Advanced with CloudWatch alarms
cat > aws-shield.tf << 'EOF'
resource "aws_shield_protection" "main" {
  name         = "memcached-ddos-protection"
  resource_arn = aws_eip.main.arn
}

resource "aws_cloudwatch_metric_alarm" "ddos_detected" {
  alarm_name          = "shield-ddos-attack-detected"
  comparison_operator = "GreaterThanThreshold"
  evaluation_periods  = 1
  metric_name         = "DDoSDetected"
  namespace           = "AWS/DDoSProtection"
  period              = 60
  statistic           = "Sum"
  threshold           = 0
  alarm_description   = "DDoS attack detected by AWS Shield"
  alarm_actions       = [aws_sns_topic.alerts.arn]

  dimensions = {
    ResourceArn = aws_eip.main.arn
  }
}

resource "aws_cloudwatch_metric_alarm" "bandwidth_spike" {
  alarm_name          = "unusual-bandwidth-spike"
  comparison_operator = "GreaterThanThreshold"
  evaluation_periods  = 2
  metric_name         = "NetworkIn"
  namespace           = "AWS/EC2"
  period              = 60
  statistic           = "Sum"
  threshold           = 10000000000  # 10 GB in 1 minute
  alarm_description   = "Possible DDoS - bandwidth spike detected"
  alarm_actions       = [aws_sns_topic.alerts.arn]
}
EOF

# Cloudflare DDoS protection (API configuration)
curl -X POST "https://api.cloudflare.com/client/v4/zones/<ZONE_ID>/firewall/rules" \
  -H "Authorization: Bearer <API_TOKEN>" \
  -H "Content-Type: application/json" \
  --data '{
    "filter": {
      "expression": "(cf.threat_score gt 14) or (cf.client.bot) or (ip.src in $memcached_blocklist)",
      "description": "Block Memcached amplification sources"
    },
    "action": "block",
    "description": "DDoS mitigation for Memcached amplification"
  }'

# Rate limiting at network edge
curl -X POST "https://api.cloudflare.com/client/v4/zones/<ZONE_ID>/rate_limits" \
  -H "Authorization: Bearer <API_TOKEN>" \
  -H "Content-Type: application/json" \
  --data '{
    "threshold": 100,
    "period": 60,
    "match": {
      "request": {
        "url": "*"
      }
    },
    "action": {
      "mode": "challenge",
      "timeout": 86400
    },
    "description": "Rate limit potential DDoS traffic"
  }'
